import React, { useState } from "react";
import InstructionBox from "../InstructionBox";
import "../../styles/modes.css";

const VisualEquivalence = () => {
  const [currentLevel, setCurrentLevel] = useState(0);

  const equivalences = [
    {
      title: "Halves to Fourths",
      left: { pieces: 2, filled: 1, label: "1/2", color: "#6366F1" },
      right: { pieces: 4, filled: 2, label: "2/4", color: "#6366F1" },
      message: "1/2 = 2/4 ✨",
      explanation: "Cut each piece in HALF → 2 pieces become 4 pieces!"
    },
    {
      title: "Halves to Eighths",
      left: { pieces: 2, filled: 1, label: "1/2", color: "#10B981" },
      right: { pieces: 8, filled: 4, label: "4/8", color: "#10B981" },
      message: "1/2 = 4/8 ✨",
      explanation: "Cut each piece into 4 parts → 1 piece becomes 4 pieces!"
    },
    {
      title: "Thirds to Sixths",
      left: { pieces: 3, filled: 1, label: "1/3", color: "#EF4444" },
      right: { pieces: 6, filled: 2, label: "2/6", color: "#EF4444" },
      message: "1/3 = 2/6 ✨",
      explanation: "Cut each piece in HALF → 1 piece becomes 2 pieces!"
    },
    {
      title: "Two-Thirds to Sixths",
      left: { pieces: 3, filled: 2, label: "2/3", color: "#F59E0B" },
      right: { pieces: 6, filled: 4, label: "4/6", color: "#F59E0B" },
      message: "2/3 = 4/6 ✨",
      explanation: "Cut each piece in HALF → 2 pieces become 4 pieces!"
    },
    {
      title: "Fourths to Eighths",
      left: { pieces: 4, filled: 1, label: "1/4", color: "#8B5CF6" },
      right: { pieces: 8, filled: 2, label: "2/8", color: "#8B5CF6" },
      message: "1/4 = 2/8 ✨",
      explanation: "Cut each piece in HALF → 1 piece becomes 2 pieces!"
    },
  ];

  const level = equivalences[currentLevel];

  const renderBoxes = (pieces, filled, color) => {
    return (
      <div className="boxes-container">
        {Array.from({ length: pieces }).map((_, i) => (
          <div
            key={i}
            className="box-segment"
            style={{
              backgroundColor: i < filled ? color : "#E5E7EB",
              border: `2px solid ${color}`,
            }}
          />
        ))}
      </div>
    );
  };

  const nextLevel = () => {
    if (currentLevel < equivalences.length - 1) {
      setCurrentLevel(currentLevel + 1);
    }
  };

  const prevLevel = () => {
    if (currentLevel > 0) {
      setCurrentLevel(currentLevel - 1);
    }
  };

  return (
    <div className="mode-container">
      <InstructionBox
        title="Visual Equivalence"
        description="Different fractions can show the SAME amount! 🤯"
      />

      <div className="equivalence-display">
        <div className="equivalence-pair">
          <div className="fraction-container">
            <div className="fraction-label">{level.left.label}</div>
            {renderBoxes(level.left.pieces, level.left.filled, level.left.color)}
          </div>

          <div className="equals-sign">
            <span>=</span>
          </div>

          <div className="fraction-container">
            <div className="fraction-label">{level.right.label}</div>
            {renderBoxes(level.right.pieces, level.right.filled, level.right.color)}
          </div>
        </div>
      </div>

      <div className="equivalence-message">
        <h2 style={{ fontSize: "2rem", color: level.left.color }}>
          {level.message}
        </h2>
        <p style={{ fontSize: "1.1rem", color: "#6B7280", marginTop: "12px" }}>
          The <strong>colored parts take up the SAME SPACE</strong>, even though they're cut into different numbers of pieces!
        </p>
        <p style={{ fontSize: "1.1rem", color: level.left.color, marginTop: "16px", fontWeight: "700", backgroundColor: "rgba(255,255,255,0.7)", padding: "12px", borderRadius: "8px" }}>
          💡 {level.explanation}
        </p>
      </div>

      <div className="level-progress">
        <span style={{ fontSize: "1.1rem", fontWeight: "700" }}>
          Level {currentLevel + 1} of {equivalences.length}
        </span>
        <div className="progress-bar">
          <div
            className="progress-fill"
            style={{ width: `${((currentLevel + 1) / equivalences.length) * 100}%` }}
          />
        </div>
      </div>

      <div className="button-group">
        <button
          onClick={prevLevel}
          disabled={currentLevel === 0}
          className="btn-modern-primary"
          style={{ opacity: currentLevel === 0 ? 0.5 : 1 }}
        >
          ← Previous
        </button>
        <button onClick={nextLevel} disabled={currentLevel === equivalences.length - 1} className="btn-modern-primary" style={{ opacity: currentLevel === equivalences.length - 1 ? 0.5 : 1 }}>
          Next →
        </button>
      </div>

      {currentLevel === equivalences.length - 1 && (
        <div className="message-box">
          <h3 style={{ color: "#10B981", fontSize: "1.5rem" }}>
            🎉 You learned equivalence!
          </h3>
          <p>When you cut pieces smaller, you get more pieces, but the colored part stays the SAME!</p>
        </div>
      )}
    </div>
  );
};

export default VisualEquivalence;
